import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const MyTasks = () => {
  const { user } = useAuth();
  const { tasks, updateTaskProgress } = useData();
  
  // State lưu giá trị nhập mới (Vì slider bị disable drag)
  const [inputs, setInputs] = useState({});
  const [reasons, setReasons] = useState({});

  // 1. Lọc và Sắp xếp: Gấp (gần deadline) lên đầu
  const myTasks = tasks
    .filter(t => t.assigneeId === user.id)
    .sort((a, b) => new Date(a.endTime) - new Date(b.endTime));

  const handleUpdateClick = (task) => {
      const newProg = inputs[task.id] !== undefined ? parseInt(inputs[task.id]) : task.progress;
      const reason = reasons[task.id] || task.reason || '';

      // 2. Logic chặn: < 90% phải có lý do
      if (newProg < 90 && !reason.trim()) {
          alert("CẢNH BÁO: Tiến độ dưới 90% bắt buộc phải nhập lý do giải trình!");
          return;
      }

      updateTaskProgress(task.id, newProg, reason);
      alert("Cập nhật tiến độ thành công!");
  };

  return (
    <div>
      <h2 style={{ color: '#003366' }}>Nhiệm vụ của tôi</h2>
      <div style={{ display: 'grid', gap: '20px' }}>
        {myTasks.map(task => {
            const now = new Date();
            const deadline = new Date(task.endTime);
            const isOverdue = now > deadline && task.progress < 100;
            const isUrgent = !isOverdue && (deadline - now) < 86400000; // < 24h

            return (
                <div key={task.id} style={{ 
                    border: isOverdue ? '2px solid red' : (isUrgent ? '2px solid orange' : '1px solid #ccc'),
                    padding: '20px', borderRadius: '8px', background: 'white'
                }}>
                    {/* LABELS */}
                    <div style={{display:'flex', justifyContent:'space-between'}}>
                        <h3 style={{margin:0}}>{task.title}</h3>
                        <div>
                            {isUrgent && <span style={{background:'orange', color:'white', padding:'4px 8px', borderRadius:'4px', marginRight:'5px'}}>CẦN HOÀN THÀNH GẤP</span>}
                            {isOverdue && <span style={{background:'red', color:'white', padding:'4px 8px', borderRadius:'4px'}}>QUÁ HẠN</span>}
                        </div>
                    </div>
                    
                    {isOverdue && <div style={{color: 'red', fontWeight: 'bold', marginTop: '10px'}}>KỶ LUẬT ÁP DỤNG: {task.disciplineName}</div>}

                    <p>
                        <strong>Thời gian:</strong> {new Date(task.startTime).toLocaleString()} ➝ <strong>{new Date(task.endTime).toLocaleString()}</strong>
                    </p>
                    <p><strong>Vai trò:</strong> {task.assignedRole} | <strong>Loại hình:</strong> {task.paymentType}</p>

                    <hr style={{margin:'15px 0', borderTop:'1px solid #eee'}}/>
                    
                    {/* SLIDER DISABLED & INPUT */}
                    <label>Tiến độ hiện tại: {task.progress}%</label>
                    <input type="range" min="0" max="100" value={task.progress} disabled style={{width:'100%', opacity: 0.7}} />
                    
                    <div style={{marginTop: '10px', display: 'flex', gap: '10px', alignItems: 'center'}}>
                        <span>Cập nhật % mới:</span>
                        <input 
                            type="number" min="0" max="100" 
                            value={inputs[task.id] !== undefined ? inputs[task.id] : task.progress}
                            onChange={e => setInputs({...inputs, [task.id]: e.target.value})}
                            style={{padding:'5px', width: '60px', fontWeight: 'bold'}}
                        />
                    </div>

                    {/* REASON AREA */}
                    {(inputs[task.id] < 90 || task.progress < 90) && (
                        <textarea 
                            placeholder="Bắt buộc nhập lý do nếu dưới 90%..."
                            value={reasons[task.id] !== undefined ? reasons[task.id] : (task.reason || '')}
                            onChange={e => setReasons({...reasons, [task.id]: e.target.value})}
                            style={{width:'100%', marginTop:'10px', height:'60px', borderColor: 'orange'}}
                        />
                    )}

                    <button onClick={() => handleUpdateClick(task)} style={{marginTop:'15px', background:'#003366', color:'white', padding:'10px 20px', border:'none', borderRadius:'4px', cursor:'pointer'}}>
                        Cập nhật tiến độ
                    </button>
                </div>
            );
        })}
      </div>
    </div>
  );
};

export default MyTasks;
